const input = $input.first().json;
const body = input.body || input;
const headers = input.headers || {};
const clean = value => String(value || '').trim();
const header = name => headers[name] || headers[name.toLowerCase()] || headers[name.toUpperCase()] || '';

function canonicalStringify(value) {
  if (value === null || typeof value !== 'object') return JSON.stringify(value);
  if (Array.isArray(value)) return '[' + value.map(canonicalStringify).join(',') + ']';
  return '{' + Object.keys(value).sort().map(key => JSON.stringify(key) + ':' + canonicalStringify(value[key])).join(',') + '}';
}

function timingSafeEqual(a, b) {
  const left = String(a || '');
  const right = String(b || '');
  let mismatch = left.length === right.length ? 0 : 1;
  const length = Math.max(left.length, right.length);
  for (let i = 0; i < length; i += 1) {
    mismatch |= (left.charCodeAt(i) || 0) ^ (right.charCodeAt(i) || 0);
  }
  return mismatch === 0;
}

async function hmacSha256Hex(secret, data) {
  if (typeof require === 'function') {
    try {
      return require('crypto').createHmac('sha256', secret).update(data).digest('hex');
    } catch (_) {}
  }
  if (globalThis.crypto?.subtle) {
    const key = await crypto.subtle.importKey('raw', new TextEncoder().encode(secret), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']);
    const signature = await crypto.subtle.sign('HMAC', key, new TextEncoder().encode(data));
    return Array.from(new Uint8Array(signature)).map(byte => byte.toString(16).padStart(2, '0')).join('');
  }
  throw new Error('No HMAC implementation available in n8n Code node');
}

const errors = [];
const secret = clean($env.INTERNAL_WEBHOOK_SECRET);
const timestamp = clean(header('x-internal-timestamp'));
const suppliedSignature = clean(header('x-internal-signature')).replace(/^sha256=/i, '');

if (!secret) errors.push('INTERNAL_WEBHOOK_SECRET is not configured');
if (!timestamp || !/^\d{12,15}$/.test(timestamp)) errors.push('x-internal-timestamp is required');
if (!suppliedSignature || !/^[a-f0-9]{64}$/i.test(suppliedSignature)) errors.push('x-internal-signature is required');

if (timestamp && Math.abs(Date.now() - Number(timestamp)) > 5 * 60 * 1000) {
  errors.push('signed request timestamp is outside the allowed 5 minute window');
}

if (errors.length === 0) {
  const canonicalBody = canonicalStringify(body);
  const expectedSignature = await hmacSha256Hex(secret, timestamp + '.' + canonicalBody);
  if (!timingSafeEqual(expectedSignature, suppliedSignature.toLowerCase())) {
    errors.push('internal webhook signature is invalid');
  }
}

const prescriptionId = clean(body.prescription_id);
const patientId = clean(body.patient_id);
const visitId = clean(body.visit_id);
const patientName = clean(body.patient_name) || 'there';
const phone = clean(body.phone);
const doctorName = clean(body.doctor_name) || $env.DEFAULT_DOCTOR_NAME || 'your doctor';
const clinicName = clean(body.clinic_name) || $env.DEFAULT_CLINIC_NAME || 'our clinic';
const pdfUrl = clean(body.pdf_url);
const medicines = Array.isArray(body.medicines) ? body.medicines : [];
const medicineSummary = medicines
  .map((m, index) => {
    const name = clean(m.medicine_name || m.name);
    const dosage = clean(m.dosage);
    const frequency = clean(m.frequency);
    const timing = clean(m.timing);
    const duration = clean(m.duration);
    const parts = [dosage, frequency, timing, duration].filter(Boolean).join(', ');
    return name ? String(index + 1) + '. ' + name + (parts ? ' - ' + parts : '') : '';
  })
  .filter(Boolean)
  .join('; ')
  .slice(0, 900) || 'As listed in the attached prescription';

if (!prescriptionId || !/^[0-9a-f-]{36}$/i.test(prescriptionId)) errors.push('prescription_id must be a UUID');
if (!patientId || !/^[0-9a-f-]{36}$/i.test(patientId)) errors.push('patient_id must be a UUID');
if (visitId && !/^[0-9a-f-]{36}$/i.test(visitId)) errors.push('visit_id must be a UUID when provided');
if (!phone || !/^\+[1-9]\d{6,14}$/.test(phone)) errors.push('phone must be E.164 format');
if (!pdfUrl || !/^https:\/\//i.test(pdfUrl)) errors.push('pdf_url must be an HTTPS URL');
const contentSid = clean($env.TWILIO_CONTENT_PRESCRIPTION_DELIVERY);
if (!contentSid) errors.push('TWILIO_CONTENT_PRESCRIPTION_DELIVERY is required for prescription cards');
if (errors.length) return [{ json: { _valid: false, _errors: errors } }];
const contentVariables = JSON.stringify({
  '1': patientName,
  '2': doctorName,
  '3': clinicName,
  '4': medicineSummary,
  '5': pdfUrl,
});
const bodyText = 'Hi ' + patientName + ', your prescription from ' + doctorName + ' at ' + clinicName + ' is ready. Medicines: ' + medicineSummary + '. Open it here: ' + pdfUrl;
return [{ json: { _valid: true, prescription_id: prescriptionId, patient_id: patientId, visit_id: visitId || null, patient_name: patientName, phone, doctor_name: doctorName, clinic_name: clinicName, pdf_url: pdfUrl, medicine_summary: medicineSummary, _to_phone: 'whatsapp:' + phone, _message_type: 'prescription_pdf', _scheduled_date: new Date().toLocaleDateString('en-CA', { timeZone: $env.TIMEZONE || 'Asia/Kolkata' }), _content_sid: contentSid, _content_variables: contentVariables, _message_body: bodyText } }];

