=UPDATE public.prescriptions
SET delivery_status = 'sent', updated_at = NOW()
WHERE id = '{{ $('Validate Delivery Payload').item.json.prescription_id }}';

=UPDATE public.prescriptions
SET delivery_status = 'failed', updated_at = NOW()
WHERE id = '{{ $('Validate Delivery Payload').item.json.prescription_id }}';
